function [scanNDir,diagDir,anlNDir,anlDiagDir] = fDirPathV01(scnDir,anlDir,scan,diagNam)%% directry path%% [scanNDir,diagDir,anlNDir,anlDiagDir] = fDirPathV01(scnDir,anlDir)%%% Written by Kei Nakamura% % 2015/7/8: created% 2020/3/11: added "A" for analysis dir%% Used in bellaEBeamPrfV02% %% main bodyscanNS = fGet3NmbStringV01(scan);  % 3 digit scan number string scanNDir = [scnDir,filesep,'Scan',scanNS];            % scan# directorydiagDir = [scanNDir,filesep,diagNam];      % scan data directoryanlNDir = [anlDir,filesep,'Scan',scanNS];   % analysis scan# directoryanlDiagDir = [anlNDir,filesep,diagNam,'A']; % analysis HPD_CCD directory
